def parse_nombre(raw):
    tokens = raw.strip().split()
    if len(tokens) < 3:
        return {"status": "review", "raw": raw, "tokens": tokens}
    return {
        "status": "ok",
        "raw": raw,
        "given": " ".join(tokens[:-2]),
        "apellido1": tokens[-2],
        "apellido2": tokens[-1],
    }
for r in ["Ana", "Ana Quispe", "Ana María Quispe Huamán"]:
    print(parse_nombre(r))

def normalize_email(raw):
    s = raw.strip().casefold()
    if s.count("@") != 1:
        raise ValueError("need exactly one @")
    local, domain = s.split("@")
    if not local or not domain or " " in s:
        raise ValueError("empty local/domain or spaces")
    return s
print(normalize_email("  A@B.COM "))
for bad in ["@b.com", "a@", "a @b.com"]:
    try:
        normalize_email(bad)
    except ValueError as e:
        print("err", bad, e)

def norm(s):
    return " ".join(s.strip().casefold().split())
print(norm("  Juan   PEREZ ") == norm("juan perez"))

def token_jaccard(a, b):
    ta, tb = set(a.casefold().split()), set(b.casefold().split())
    if not ta and not tb:
        return 1.0
    return len(ta & tb) / len(ta | tb)
print(round(token_jaccard("Juan Perez", "Juan P Perez"), 2))

